-- ============================================================
-- YLArabaslik LISTE tipi tum bolumler import (v7 dedup)
-- Kaynak: TUM_BOLUMLER_TURKCE.xlsx (DB Format) — guncel versiyon
-- TablTipi=2 (Liste / numarali / fiyatli)
-- - 11 ana baslik, prefix-strip + canonical + fuzzy + typo override pipeline
-- - Fiyat NULL, ParaBirimi NULL (sablon panelinden manuel girilir)
-- - Idempotent: ayni isimde grup varsa tekrar olusturulmaz; eski detaylar silinir
-- - Atlanan bolumler: ÖLÇÜLER, AĞIRLIKLAR (Tablo - ayri script), NOTLAR
-- ============================================================

DO $$
DECLARE
    grup_id INT;
BEGIN

    -- ======== DEVEBOYNU (55 kalem) ========
    SELECT "Id" INTO grup_id FROM "YLArabaslikGruplar" WHERE "GrupAdi" = 'DEVEBOYNU' LIMIT 1;
    IF grup_id IS NULL THEN
             "TablTipi","SortOrder","IsActive","CreatedDate","CreatedBy")
        VALUES ('DEVEBOYNU', '', '', '', '', '', '', 2, 10, TRUE, NOW(), 'Excel Import')
        RETURNING "Id" INTO grup_id;
    END IF;
    DELETE FROM "YLArabaslikDetaylar" WHERE "GrupId" = grup_id;

    -- ======== YÜKLEME PLATFORMU (133 kalem) ========
    SELECT "Id" INTO grup_id FROM "YLArabaslikGruplar" WHERE "GrupAdi" = 'YÜKLEME PLATFORMU' LIMIT 1;
